55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	};
74	const COMPONENT_INSURANCE_VALUE = 250;
75	
76	const DEDUCTIBLE = 100;
77	const CAP_MULTIPLIER = 2;
78	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
79	const REIMBURSEMENT_HALF_RATE = 0.5;
80	
81	const INITIAL_ASSESSMENT_RATE = 0.1;
82	const CURSE_SURCHARGE_RATE = 0.5;
83	const HIGH_ENCHANTMENT_RATE = 0.3;
84	const HIGH_ENCHANTMENT_THRESHOLD = 5;
85	const LOYALTY_DISCOUNT_RATE = 0.2;
86	const LOYALTY_YEARS_THRESHOLD = 2;
87	const FOLLOWUP_DISCOUNT_RATE = 0.15;
88	const PROCESSING_FEE = 5;
89	const FLOAT_PRECISION_DIGITS = 6;
90	
91	const isKnownItemType = (type: string): boolean => {
92	  return COMPONENT_TYPES.has(type) || type in BASE_PREMIUM;
93	};
94	
95	const assertKnownItems = (items: Item[]): void => {
96	  for (const item of items) {
97	    if (!isKnownItemType(item.type)) {
98	      throw new Error(`unknown item type: ${item.type}`);
99	    }
100	  }
101	};
102	
103	const itemOwnBase = (item: Item): number => {
104	  return COMPONENT_TYPES.has(item.type)
105	    ? COMPONENT_PRICE
106	    : BASE_PREMIUM[item.type];
107	};
108	
109	const itemSurcharge = (item: Item): number => {
110	  const own = itemOwnBase(item);
111	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * own : 0;
112	  const highEnchantment =
113	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
114	      ? HIGH_ENCHANTMENT_RATE * own
115	      : 0;
116	  return curse + highEnchantment;
117	};
118	
119	const componentBase = (count: number): number => {
120	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
121	};
122	
123	const countBy = <T>(
124	  list: T[],
125	  keyOf: (element: T) => string,
126	): Map<string, number> => {
127	  const counts = new Map<string, number>();
128	  for (const element of list) {
129	    const key = keyOf(element);
130	    counts.set(key, (counts.get(key) ?? 0) + 1);
131	  }
132	  return counts;
133	};
134	
135	const itemBaseTotal = (items: Item[]): number => {
136	  let total = 0;
137	  for (const [type, count] of countBy(items, (item) => item.type)) {
138	    total += COMPONENT_TYPES.has(type)
139	      ? componentBase(count)
140	      : BASE_PREMIUM[type] * count;
141	  }
142	  return total;
143	};
144	
145	const quotePremium = (
146	  step: QuoteStep,
147	  customer: Customer,
148	  isFollowUp: boolean,
149	): number => {
150	  assertKnownItems(step.items);
151	  const policyBase = itemBaseTotal(step.items);
152	  const surcharges = step.items.reduce(
153	    (sum, item) => sum + itemSurcharge(item),
154	    0,
155	  );
156	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
157	  const loyaltyDiscount =
158	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
159	      ? LOYALTY_DISCOUNT_RATE * policyBase
160	      : 0;
161	  const followUpDiscount = isFollowUp ? FOLLOWUP_DISCOUNT_RATE * policyBase : 0;
162	  const premium =
163	    policyBase +
164	    surcharges +
165	    initialAssessment -
166	    loyaltyDiscount -
167	    followUpDiscount +
168	    PROCESSING_FEE;
169	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
170	};
171	
172	interface Policy {
173	  items: Item[];
174	  remainingCap: number;
175	}
176	
177	const itemInsuranceValue = (item: Item): number => {
178	  return COMPONENT_TYPES.has(item.type)
179	    ? COMPONENT_INSURANCE_VALUE
180	    : INSURANCE_VALUE[item.type];
181	};
182	
183	const insuranceSum = (items: Item[]): number => {
184	  return items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
185	};
186	
187	const reimbursableAmount = (amount: number, item: Item): number => {
188	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
189	    ? REIMBURSEMENT_HALF_RATE * amount
190	    : amount;
191	};
192	
193	const damagePayout = (damage: Damage, items: Item[]): number => {
194	  const item = items.find((candidate) => candidate.type === damage.itemType);
195	  return Math.max(0, reimbursableAmount(damage.amount, item!) - DEDUCTIBLE);
196	};
197	
198	const assertDamagesCovered = (damages: Damage[], items: Item[]): void => {
199	  const insured = countBy(items, (item) => item.type);
200	  for (const [type, count] of countBy(damages, (damage) => damage.itemType)) {
201	    if (count > (insured.get(type) ?? 0)) {
202	      throw new Error(`claim references more ${type} damages than insured`);
203	    }
204	  }
205	};
206	
207	const claimResult = (step: ClaimStep, policies: Policy[]): ClaimResult => {
208	  const policy = policies[step.policy];
209	  assertDamagesCovered(step.incident.damages, policy.items);
210	  const requested = step.incident.damages.reduce(
211	    (sum, damage) => sum + damagePayout(damage, policy.items),
212	    0,
213	  );
214	  const payout = Math.min(requested, policy.remainingCap);
215	  policy.remainingCap -= payout;
216	  return { payout, remainingCap: policy.remainingCap };
217	};
218	
219	export const runScenario = (scenario: Scenario): ScenarioResult => {
220	  const policies: Policy[] = [];
221	  let quotesSeen = 0;
222	  const results = scenario.steps.map((step, index): Result => {
223	    if (step.op === "claim") {
224	      return claimResult(step, policies);
225	    }
226	    const isFollowUp = quotesSeen >= 1;
227	    quotesSeen += 1;
228	    policies[index] = {
229	      items: step.items,
230	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
231	    };
232	    return { premium: quotePremium(step, scenario.customer, isFollowUp) };
233	  });
234	  return { results };
235	};
